from PySide6 import QtCore, QtWidgets
from PySide6.QtCore import Qt

from videotrans.configure.config import tr,settings,params,logger,app_cfg
from videotrans.util import tools


class Ui_minimaxform(object):
    def setupUi(self, minimaxform):
        self.has_done = False
        minimaxform.setObjectName("minimaxform")
        minimaxform.setWindowModality(QtCore.Qt.NonModal)
        minimaxform.resize(600, 600)
        sizePolicy = QtWidgets.QSizePolicy(QtWidgets.QSizePolicy.Fixed, QtWidgets.QSizePolicy.Fixed)
        sizePolicy.setHorizontalStretch(0)
        sizePolicy.setVerticalStretch(0)
        sizePolicy.setHeightForWidth(minimaxform.sizePolicy().hasHeightForWidth())
        minimaxform.setSizePolicy(sizePolicy)
        minimaxform.setMaximumSize(QtCore.QSize(600, 600))

        v1 = QtWidgets.QVBoxLayout(minimaxform)
        h2 = QtWidgets.QHBoxLayout()

        h4 = QtWidgets.QHBoxLayout()

        self.label_0 = QtWidgets.QPushButton()
        self.label_0.setGeometry(QtCore.QRect(10, 10, 580, 35))
        self.label_0.setStyleSheet("background-color: rgba(255, 255, 255,0);text-align:left")
        self.label_0.setText(
            'MiniMax AI')
        v1.addWidget(self.label_0)

        self.label_2 = QtWidgets.QLabel(minimaxform)
        self.label_2.setMinimumSize(QtCore.QSize(0, 35))
        self.label_2.setSizeIncrement(QtCore.QSize(0, 35))
        self.label_2.setObjectName("label_2")
        self.minimax_key = QtWidgets.QLineEdit(minimaxform)
        self.minimax_key.setMinimumSize(QtCore.QSize(0, 35))
        self.minimax_key.setObjectName("minimax_key")
        h2.addWidget(self.label_2)
        h2.addWidget(self.minimax_key)
        v1.addLayout(h2)

        h_api = QtWidgets.QHBoxLayout()
        self.label_api = QtWidgets.QLabel()
        self.label_api.setObjectName("label_api")
        self.label_api.setText("API URL")
        self.minimax_api = QtWidgets.QLineEdit()
        self.minimax_api.setMinimumSize(QtCore.QSize(0, 35))
        self.minimax_api.setObjectName("minimax_api")
        self.minimax_api.setPlaceholderText("api.minimax.io")
        h_api.addWidget(self.label_api)
        h_api.addWidget(self.minimax_api)
        v1.addLayout(h_api)

        h_model = QtWidgets.QHBoxLayout()
        self.label_selectmodel = QtWidgets.QLabel()
        self.label_selectmodel.setObjectName("label_selectmodel")
        self.label_selectmodel.setText("Model")
        self.minimax_model = QtWidgets.QComboBox()
        self.minimax_model.setMinimumSize(QtCore.QSize(0, 35))
        self.minimax_model.setObjectName("minimax_model")
        h_model.addWidget(self.label_selectmodel)
        h_model.addWidget(self.minimax_model)
        v1.addLayout(h_model)
        h_token = QtWidgets.QHBoxLayout()

        label_token = QtWidgets.QLabel()
        label_token.setObjectName("label_token")
        label_token.setText(tr("Maximum output token"))
        self.max_token = QtWidgets.QLineEdit()
        self.max_token.setMinimumSize(QtCore.QSize(0, 35))
        self.max_token.setObjectName("max_token")

        h_token.addWidget(label_token)
        h_token.addWidget(self.max_token)
        v1.addLayout(h_token)

        self.label_allmodels = QtWidgets.QLabel()
        self.label_allmodels.setObjectName("label_allmodels")
        self.label_allmodels.setText(
            tr("Fill in all available models, separated by commas. After filling in, you can select them above"))
        v1.addWidget(self.label_allmodels)

        self.edit_allmodels = QtWidgets.QPlainTextEdit()
        self.edit_allmodels.setObjectName("edit_allmodels")
        v1.addWidget(self.edit_allmodels)

        self.label_4 = QtWidgets.QLabel(minimaxform)
        self.label_4.setObjectName("label_4")

        self.template = QtWidgets.QPlainTextEdit(minimaxform)
        self.template.setObjectName("template")
        self.template.setReadOnly(True)
        v1.addWidget(self.label_4)
        v1.addWidget(self.template)

        self.set = QtWidgets.QPushButton(minimaxform)
        self.set.setMinimumSize(QtCore.QSize(0, 35))
        self.set.setObjectName("set")

        self.test = QtWidgets.QPushButton()
        self.test.setMinimumSize(QtCore.QSize(0, 30))
        self.test.setObjectName("test")
        self.test.setText(tr("Test"))

        help_btn = QtWidgets.QPushButton()
        help_btn.setMinimumSize(QtCore.QSize(0, 35))
        help_btn.setStyleSheet("background-color: rgba(255, 255, 255,0)")
        help_btn.setObjectName("help_btn")
        help_btn.setCursor(Qt.PointingHandCursor)
        help_btn.setText(tr("Fill out the tutorial"))
        help_btn.clicked.connect(lambda: tools.open_url(url='https://pyvideotrans.com/minimaxi'))

        h4.addWidget(self.set)
        h4.addWidget(self.test)
        h4.addWidget(help_btn)
        v1.addLayout(h4)
        self.template.setPlainText(tr("Prompt: Please open the {} file directly to modify it", 'minimax', 'minimax'))

        self.retranslateUi(minimaxform)
        QtCore.QMetaObject.connectSlotsByName(minimaxform)


    def update_ui(self):
        allmodels_str = settings.get('minimax_model','')
        if not allmodels_str:
            allmodels_str = 'MiniMax-M2.7,MiniMax-M2.7-highspeed,MiniMax-M2.5,MiniMax-M2.5-highspeed'
        allmodels = str(allmodels_str).split(',')
        self.minimax_model.clear()
        self.minimax_model.addItems(allmodels)
        self.edit_allmodels.setPlainText(allmodels_str)

        self.minimax_key.setText(params.get("minimax_key",''))
        self.minimax_api.setText(params.get("minimax_api",''))
        self.max_token.setText(str(params.get("minimax_max_tokens",'8192')))
        self.minimax_model.setCurrentText(params.get("minimax_model",''))

    def retranslateUi(self, minimaxform):
        minimaxform.setWindowTitle("MiniMax AI")
        self.label_2.setText(tr("SK"))
        self.label_4.setText(tr("{lang} represents the target language name, do not delete it."))
        self.set.setText(tr('Save'))
